const callback = $json.callback_query || {};
const data = String(callback.data || '').trim();
const [action, related_entity_type, related_entity_id] = data.split('|');

const mapping = {
  restaurant_booking: {
    table_name: 'prenotazioni',
    field_name: 'stato',
    accept_status: 'CONFERMATA',
    reject_status: 'RIFIUTATA',
    accept_label: 'Prenotazione ristorante confermata',
    reject_label: 'Prenotazione ristorante rifiutata',
  },
  hotel_booking: {
    table_name: 'hotel_bookings',
    field_name: 'booking_status',
    accept_status: 'confirmed',
    reject_status: 'rejected',
    accept_label: 'Richiesta soggiorno confermata',
    reject_label: 'Richiesta soggiorno rifiutata',
  },
  appointment: {
    table_name: 'appointments',
    field_name: 'stato',
    accept_status: 'confirmed',
    reject_status: 'rejected',
    accept_label: 'Appuntamento confermato',
    reject_label: 'Appuntamento rifiutato',
  },
};

const target = mapping[related_entity_type] || null;
const operatorName = callback.from?.first_name || 'Team';
const originalText = callback.message?.text || 'Messaggio non disponibile';
const normalizedAction = String(action || '').trim().toLowerCase();
const actionTimestamp = new Date().toISOString();
const isAccept = normalizedAction === 'accept';
const isReject = normalizedAction === 'reject';

return [{
  json: {
    ...$json,
    callback_action: normalizedAction,
    related_entity_type: related_entity_type || '',
    related_entity_id: related_entity_id || '',
    operator_name: operatorName,
    original_text: originalText,
    action_timestamp: actionTimestamp,
    rejection_reason: isReject ? `Rifiutata da Telegram da ${operatorName}` : null,
    new_status: target ? (isReject ? target.reject_status : target.accept_status) : '',
    status_label: target ? (isReject ? target.reject_label : target.accept_label) : '',
    ...target,
    is_supported: Boolean(target && (isAccept || isReject) && related_entity_id),
  },
}];

const input = $('Parse Callback Data1').item.json;
const isReject = input.callback_action === 'reject';

return [{
  json: {
    ...input,
    callback_answer_text: input.status_label + ' da ' + input.operator_name,
    edited_message_text: [
      input.original_text,
      '',
      'Aggiornamento: ' + (isReject ? 'rifiutata' : 'accettata'),
      (isReject ? 'Rifiutata da: ' : 'Accettata da: ') + input.operator_name,
    ].join('\n'),
  },
}];

const input = $json;
return [{
  json: {
    ...input,
    callback_answer_text: 'Azione non supportata o dati callback non validi.',
    edited_message_text: input.original_text || 'Azione non supportata.',
  },
}];

const action = $('Parse Callback Data1').item.json;
const row = $('Get Appointment Row').item.json || {};
const tenant = $('Get Appointment Tenant Row').item.json || {};

const normalizeEmail = (value) => String(value || '').trim().toLowerCase();
const customerRecipient = normalizeEmail(row.email);
const internalRecipient = normalizeEmail(
  tenant.notification_email || tenant.billing_email || tenant.mail || ''
);

const activity = tenant.nome_attivita || tenant.nome_ristorante || tenant.hotel_name || row.nome || row.tenant_id || 'Zirèl';
const now = action.action_timestamp;
const eventType = action.callback_action === 'reject' ? 'rejected' : 'confirmed';
const customerTemplate = action.callback_action === 'reject' ? 'appointment_rejected' : 'appointment_confirmed';

const payload = {
  tenant_id: row.tenant_id,
  nome_attivita: activity,
  dashboard_url: 'https://dashboard.zirel.org?tab=prenotazioni',
  appointment_id: row.id,
  nome: row.nome || 'Cliente',
  telefono: row.telefono || null,
  email: row.email || null,
  motivo: row.motivo || row.note || 'N/D',
  note: row.note || '',
  data_appuntamento: row.data_appuntamento || null,
  data_appuntamento_label: row.data_appuntamento || null,
  orario: row.orario || null,
  rejection_reason: action.rejection_reason || null,
  status: action.new_status,
  actor: `telegram:${action.operator_name}`,
};

const rows = [];
const dedupeBase = `telegram:${row.tenant_id}:${row.id}:${eventType}:${now}`;

if (customerRecipient) {
  rows.push({
    json: {
      tenant_id: row.tenant_id,
      channel: 'email_guest_appointment',
      template_key: customerTemplate,
      related_entity_type: 'appointment',
      related_entity_id: row.id,
      status: 'pending',
      retry_count: 0,
      max_retries: 5,
      next_retry_at: now,
      trace_id: dedupeBase,
      dedupe_key: `email_guest_appointment:${dedupeBase}`,
      recipient_email: customerRecipient,
      payload,
    },
  });
}

if (internalRecipient) {
  rows.push({
    json: {
      tenant_id: row.tenant_id,
      channel: 'email_internal_appointment',
      template_key: 'appointment_internal_status_update',
      related_entity_type: 'appointment',
      related_entity_id: row.id,
      status: 'pending',
      retry_count: 0,
      max_retries: 5,
      next_retry_at: now,
      trace_id: `${dedupeBase}:internal`,
      dedupe_key: `email_internal_appointment:${dedupeBase}`,
      recipient_email: internalRecipient,
      payload,
    },
  });
}

return rows;

